import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

function Home() {
    const [osList, setOsList] = useState([]);

    const [filtroNumero, setFiltroNumero] = useState('');
    const [filtroStatus, setFiltroStatus] = useState('todos');
    const [filtroCliente, setFiltroCliente] = useState('');

    const [pagina, setPagina] = useState(1);

    const itensPorPagina = 10;

    const [totalAbertas, setTotalAbertas] = useState(0);
    const [totalConcluidas, setTotalConcluidas] = useState(0);
    const [faturamentoMes, setFaturamentoMes] = useState(0);

    useEffect(() => {
        carregarOS();
    }, []);

    const carregarOS = async () => {
        try {
            const res = await api.get('/os');

            const data = res.data;

            setOsList(data);

            const abertas = data.filter(
                os => os.status_os !== 'concluido'
            ).length;

            const concluidas = data.filter(
                os => os.status_os === 'concluido'
            ).length;

            const mesAtual = new Date().getMonth();
            const anoAtual = new Date().getFullYear();

            const fatMes = data.reduce((acc, os) => {
                if (
                    os.status_os === 'concluido' &&
                    os.data_conclusao
                ) {
                    const dataConc = new Date(os.data_conclusao);

                    if (
                        dataConc.getMonth() === mesAtual &&
                        dataConc.getFullYear() === anoAtual
                    ) {
                        const total =
                            (parseFloat(os.preco_final) || 0) +
                            (parseFloat(os.valor_deslocamento) || 0);

                        return acc + total;
                    }
                }

                return acc;
            }, 0);

            setTotalAbertas(abertas);
            setTotalConcluidas(concluidas);
            setFaturamentoMes(fatMes);

        } catch (err) {
            console.error(err);
        }
    };

    const osFiltradas = osList.filter(os => {

        if (
            filtroNumero &&
            !os.numero_os
                ?.toLowerCase()
                .includes(filtroNumero.toLowerCase())
        ) {
            return false;
        }

        if (
            filtroStatus === 'abertos' &&
            os.status_os === 'concluido'
        ) {
            return false;
        }

        if (
            filtroStatus === 'concluidos' &&
            os.status_os !== 'concluido'
        ) {
            return false;
        }

        if (
            filtroCliente &&
            !os.cliente_nome
                ?.toLowerCase()
                .includes(filtroCliente.toLowerCase())
        ) {
            return false;
        }

        return true;
    });

    const totalPaginas = Math.ceil(
        osFiltradas.length / itensPorPagina
    );

    const osExibidas = osFiltradas.slice(
        (pagina - 1) * itensPorPagina,
        pagina * itensPorPagina
    );

    return (
        <div>

            {/* TÍTULO */}
            <div
                style={{
                    textAlign: 'center',
                    marginBottom: '2rem'
                }}
            >
                <h1
                    className="card"
                    style={{
                        display: 'inline-block',
                        background:
                            'linear-gradient(135deg, #1e3c72, #2a5298)',
                        color: 'white',
                        padding: '12px 28px',
                        borderRadius: '60px',
                        fontSize: '1.8rem'
                    }}
                >
                    📊 DASHBOARD - MWR SISTEMA
                </h1>
            </div>

            {/* CARDS PRINCIPAIS */}
            <div
                style={{
                    display: 'flex',
                    gap: '20px',
                    justifyContent: 'center',
                    marginBottom: '20px',
                    flexWrap: 'wrap'
                }}
            >

                {/* OS ABERTAS */}
                <div
                    className="card"
                    style={{
                        width: '220px',
                        textAlign: 'center',
                        borderTop: '5px solid #ffc107'
                    }}
                >
                    <div style={{ fontSize: '2.2rem' }}>
                        🟠
                    </div>

                    <div>
                        <strong>OS Abertas</strong>
                    </div>

                    <div
                        style={{
                            fontSize: '28px',
                            fontWeight: 'bold'
                        }}
                    >
                        {totalAbertas}
                    </div>
                </div>

                {/* OS CONCLUÍDAS */}
                <div
                    className="card"
                    style={{
                        width: '220px',
                        textAlign: 'center',
                        borderTop: '5px solid #28a745'
                    }}
                >
                    <div style={{ fontSize: '2.2rem' }}>
                        ✅
                    </div>

                    <div>
                        <strong>OS Concluídas</strong>
                    </div>

                    <div
                        style={{
                            fontSize: '28px',
                            fontWeight: 'bold'
                        }}
                    >
                        {totalConcluidas}
                    </div>
                </div>

            </div>

            {/* FATURAMENTO MAIS DISCRETO */}
            <div
                style={{
                    display: 'flex',
                    justifyContent: 'center',
                    marginBottom: '30px'
                }}
            >
                <div
                    className="card"
                    style={{
                        width: '180px',
                        textAlign: 'center',
                        borderTop: '5px solid #007bff',
                        padding: '15px'
                    }}
                >
                    <div style={{ fontSize: '1.8rem' }}>
                        💰
                    </div>

                    <div
                        style={{
                            fontSize: '14px',
                            marginBottom: '5px'
                        }}
                    >
                        <strong>Faturamento (mês)</strong>
                    </div>

                    <div
                        style={{
                            fontSize: '24px',
                            fontWeight: 'bold'
                        }}
                    >
                        R$ {faturamentoMes.toFixed(2)}
                    </div>
                </div>
            </div>

            {/* FILTROS */}
            <div className="filtros-container">

                <input
                    type="text"
                    placeholder="🔍 Nº da OS"
                    value={filtroNumero}
                    onChange={e =>
                        setFiltroNumero(e.target.value)
                    }
                    style={{ flex: 1 }}
                />

                <select
                    value={filtroStatus}
                    onChange={e =>
                        setFiltroStatus(e.target.value)
                    }
                >
                    <option value="todos">
                        Todos status
                    </option>

                    <option value="abertos">
                        Somente abertos
                    </option>

                    <option value="concluidos">
                        Somente concluídos
                    </option>
                </select>

                <input
                    type="text"
                    placeholder="👤 Nome do cliente"
                    value={filtroCliente}
                    onChange={e =>
                        setFiltroCliente(e.target.value)
                    }
                    style={{ flex: 1 }}
                />
            </div>

            {/* TABELA */}
            <div className="table-responsive">

                <table>

                    <thead>
                        <tr>
                            <th>Nº OS</th>
                            <th>Cliente</th>
                            <th>Equipamento</th>
                            <th>Status</th>
                            <th>Valor Total</th>
                            <th>Ações</th>
                        </tr>
                    </thead>

                    <tbody>

                        {osExibidas.length === 0 ? (

                            <tr>
                                <td
                                    colSpan="6"
                                    style={{
                                        textAlign: 'center',
                                        padding: '40px'
                                    }}
                                >
                                    Nenhuma OS encontrada
                                </td>
                            </tr>

                        ) : (

                            osExibidas.map(os => {

                                const totalValor = (
                                    (parseFloat(os.preco_final) || 0) +
                                    (parseFloat(os.valor_deslocamento) || 0)
                                ).toFixed(2);

                                return (
                                    <tr key={os.id}>

                                        <td>
                                            {os.numero_os}
                                        </td>

                                        <td>
                                            {os.cliente_nome}
                                        </td>

                                        <td>
                                            {os.equipamento} {os.modelo}
                                        </td>

                                        <td>
                                            <span
                                                style={{
                                                    backgroundColor:
                                                        os.status_os === 'concluido'
                                                            ? '#28a745'
                                                            : '#ffc107',
                                                    padding: '4px 10px',
                                                    borderRadius: '30px',
                                                    fontSize: '12px',
                                                    fontWeight: 'bold',
                                                    color:
                                                        os.status_os === 'concluido'
                                                            ? '#fff'
                                                            : '#000'
                                                }}
                                            >
                                                {
                                                    os.status_os === 'concluido'
                                                        ? 'CONCLUÍDO'
                                                        : 'ABERTO'
                                                }
                                            </span>
                                        </td>

                                        <td>
                                            R$ {totalValor}
                                        </td>

                                        <td>

                                            <Link to={`/os/${os.id}`}>
                                                <button
                                                    className="btn btn-primary"
                                                    style={{
                                                        marginRight: '5px'
                                                    }}
                                                >
                                                    Ver
                                                </button>
                                            </Link>

                                            <Link to={`/os/editar/${os.id}`}>
                                                <button className="btn btn-warning">
                                                    Editar
                                                </button>
                                            </Link>

                                        </td>

                                    </tr>
                                );
                            })

                        )}

                    </tbody>

                </table>

            </div>

            {/* PAGINAÇÃO */}
            {totalPaginas > 1 && (

                <div
                    style={{
                        display: 'flex',
                        justifyContent: 'center',
                        gap: '15px',
                        marginTop: '20px',
                        alignItems: 'center'
                    }}
                >

                    <button
                        className="btn btn-secondary"
                        onClick={() =>
                            setPagina(p =>
                                Math.max(1, p - 1)
                            )
                        }
                        disabled={pagina === 1}
                    >
                        Anterior
                    </button>

                    <span>
                        Página {pagina} de {totalPaginas}
                    </span>

                    <button
                        className="btn btn-secondary"
                        onClick={() =>
                            setPagina(p =>
                                Math.min(totalPaginas, p + 1)
                            )
                        }
                        disabled={pagina === totalPaginas}
                    >
                        Próxima
                    </button>

                </div>

            )}

        </div>
    );
}

export default Home;
